import{_ as t,o as r,c as d,ai as a}from"./chunks/framework.LYGRWSbL.js";const p=JSON.parse('{"title":"Le datif","description":"","frontmatter":{"prev":{"text":"Introduction Module 5","link":"/module-5-aller-plus-loin/"}},"headers":[],"relativePath":"module-5-aller-plus-loin/datif.md","filePath":"module-5-aller-plus-loin/datif.md","lastUpdated":1773298982000}'),n={name:"module-5-aller-plus-loin/datif.md"};function i(s,e,l,o,m,u){return r(),d("div",null,[...e[0]||(e[0]=[a('<h1 id="le-datif" tabindex="-1">Le datif <a class="header-anchor" href="#le-datif" aria-label="Permalink to “Le datif”">​</a></h1><p><strong>Prérequis :</strong> <a href="./../module-4-le-temps/expressions-de-temps.html">Expressions de temps</a></p><p><strong>Objectif :</strong> former et utiliser le datif - le cas de l&#39;objet indirect.</p><p>Le datif répond à la question &quot;à qui ?&quot; ou &quot;pour qui ?&quot;. C&#39;est le cas du bénéficiaire de l&#39;action.</p><h2 id="les-articles-au-datif" tabindex="-1">Les articles au datif <a class="header-anchor" href="#les-articles-au-datif" aria-label="Permalink to “Les articles au datif”">​</a></h2><div class="mt-4 overflow-hidden rounded-xl border border-gray-200"><table class="w-full text-sm"><thead><tr class="bg-gray-50"><th class="p-3 text-left font-semibold text-gray-600"></th><th class="p-3 text-center font-semibold text-blue-700">Masculin</th><th class="p-3 text-center font-semibold text-red-600">Féminin</th><th class="p-3 text-center font-semibold text-green-700">Neutre</th><th class="p-3 text-center font-semibold text-gray-700">Pluriel</th></tr></thead><tbody><tr class="border-t border-gray-100"><td class="p-3 font-medium text-gray-700">Defini</td><td class="p-3 text-center font-bold text-blue-700">dem</td><td class="p-3 text-center font-bold text-red-600">der</td><td class="p-3 text-center font-bold text-green-700">dem</td><td class="p-3 text-center font-bold text-gray-700">den</td></tr><tr class="border-t border-gray-100 bg-gray-50"><td class="p-3 font-medium text-gray-700">Indefini</td><td class="p-3 text-center font-bold text-blue-700">einem</td><td class="p-3 text-center font-bold text-red-600">einer</td><td class="p-3 text-center font-bold text-green-700">einem</td><td class="p-3 text-center text-gray-400">-</td></tr></tbody></table></div><div class="tip custom-block"><p class="custom-block-title">Le masculin et le neutre partagent la même forme au datif</p><p><em>dem</em> pour les deux (défini), <em>einem</em> pour les deux (indefini). Seul le féminin est différent : <em>der</em> et <em>einer</em>. A noter : au datif, le féminin <em>der</em> ressemble au masculin nominatif - ne pas confondre.</p></div><h2 id="objet-indirect-a-qui" tabindex="-1">Objet indirect : à qui ? <a class="header-anchor" href="#objet-indirect-a-qui" aria-label="Permalink to “Objet indirect : à qui ?”">​</a></h2><p>Quand une phrase a deux objets, le bénéficiaire de l&#39;action (objet indirect) est au datif, et l&#39;objet donné est à l&#39;accusatif.</p><div class="mt-4 p-4 rounded-xl border border-gray-200"><div class="grid grid-cols-4 gap-2 text-center"><div class="bg-blue-50 border border-blue-200 rounded p-2"><div class="text-xs text-blue-500 font-medium">Sujet (nom.)</div><div class="font-bold text-blue-800">Ich</div></div><div class="bg-green-50 border border-green-200 rounded p-2"><div class="text-xs text-green-500 font-medium">Verbe</div><div class="font-bold text-green-800">gebe</div></div><div class="bg-orange-50 border border-orange-200 rounded p-2"><div class="text-xs text-orange-500 font-medium">Datif (a qui ?)</div><div class="font-bold text-orange-800">dem Kind</div></div><div class="bg-red-50 border border-red-200 rounded p-2"><div class="text-xs text-red-500 font-medium">Accusatif (quoi ?)</div><div class="font-bold text-red-800">das Buch.</div></div></div><div class="text-sm text-gray-500 text-center mt-3">Je donne le livre a l&#39;enfant.</div></div><p>Autres exemples :</p><ul><li><em>Er schreibt <strong>seiner Mutter</strong> einen Brief.</em> - Il ecrit une lettre a sa mere.</li><li><em>Sie zeigt <strong>dem Mann</strong> den Weg.</em> - Elle montre le chemin a l&#39;homme.</li><li><em>Wir kaufen <strong>unserem Freund</strong> ein Geschenk.</em> - Nous achetons un cadeau a notre ami.</li></ul><div class="warning custom-block"><p class="custom-block-title">En allemand, le datif précède l&#39;accusatif</p><p>Contrairement au français &quot;je donne le livre a l&#39;enfant&quot; (COD avant COI), l&#39;allemand place l&#39;objet au datif avant l&#39;objet a l&#39;accusatif : <em>Ich gebe dem Kind das Buch</em> (datif, puis accusatif). C&#39;est la règle lorsque les deux objets sont des noms.</p></div><h2 id="les-pronoms-personnels-au-datif" tabindex="-1">Les pronoms personnels au datif <a class="header-anchor" href="#les-pronoms-personnels-au-datif" aria-label="Permalink to “Les pronoms personnels au datif”">​</a></h2><table tabindex="0"><thead><tr><th>Nominatif</th><th>Datif</th><th>Sens</th></tr></thead><tbody><tr><td>ich</td><td><strong>mir</strong></td><td>me / a moi</td></tr><tr><td>du</td><td><strong>dir</strong></td><td>te / a toi</td></tr><tr><td>er</td><td><strong>ihm</strong></td><td>lui</td></tr><tr><td>sie</td><td><strong>ihr</strong></td><td>lui (a elle)</td></tr><tr><td>es</td><td><strong>ihm</strong></td><td>lui (neutre)</td></tr><tr><td>wir</td><td><strong>uns</strong></td><td>nous</td></tr><tr><td>ihr</td><td><strong>euch</strong></td><td>vous</td></tr><tr><td>sie/Sie</td><td><strong>ihnen / Ihnen</strong></td><td>leur / a vous</td></tr></tbody></table><ul><li><em>Kannst du <strong>mir</strong> helfen ?</em> - Tu peux m&#39;aider ?</li><li><em>Ich gebe <strong>dir</strong> das Buch.</em> - Je te donne le livre.</li><li><em>Es gefallt <strong>mir</strong>.</em> - Ca me plait. (litt. &quot;ca plait a moi&quot;)</li></ul><h2 id="verbes-qui-prennent-le-datif" tabindex="-1">Verbes qui prennent le datif <a class="header-anchor" href="#verbes-qui-prennent-le-datif" aria-label="Permalink to “Verbes qui prennent le datif”">​</a></h2><p>Ces verbes exigent un complément au datif - ils n&#39;ont pas d&#39;objet direct.</p><table tabindex="0"><thead><tr><th>Verbe</th><th>Sens</th><th>Exemple</th></tr></thead><tbody><tr><td>helfen</td><td>aider</td><td><em>Ich helfe <strong>dem</strong> Mann.</em></td></tr><tr><td>gefallen</td><td>plaire</td><td><em>Berlin gefallt <strong>mir</strong>.</em></td></tr><tr><td>gehoren</td><td>appartenir</td><td><em>Das gehorte <strong>meinem</strong> Vater.</em></td></tr><tr><td>danken</td><td>remercier</td><td><em>Ich danke <strong>dir</strong>.</em></td></tr><tr><td>antworten</td><td>répondre</td><td><em>Antworte <strong>dem</strong> Lehrer.</em></td></tr><tr><td>schmecken</td><td>avoir bon gout</td><td><em>Das schmeckt <strong>mir</strong> gut.</em></td></tr><tr><td>fehlen</td><td>manquer</td><td><em>Du fehlst <strong>mir</strong>.</em></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">gefallen - la logique est inversee par rapport au français</p><p><em>Berlin gefallt mir</em> signifie &quot;Berlin me plait&quot; - mais grammaticalement c&#39;est &quot;Berlin plait a moi&quot; (<em>mir</em> = datif). Le sujet grammatical est Berlin, pas <em>mir</em>. Donc : <em>Berlin gefallt mir</em> (singulier), <em>Die Bucher gefallen mir</em> (pluriel) - le verbe s&#39;accorde avec le sujet, pas avec <em>mir</em>.</p></div><h2 id="le-pluriel-au-datif-ajout-de-n" tabindex="-1">Le pluriel au datif : ajout de -n <a class="header-anchor" href="#le-pluriel-au-datif-ajout-de-n" aria-label="Permalink to “Le pluriel au datif : ajout de -n”">​</a></h2><p>Au datif pluriel, les noms prennent un <em>-n</em> supplementaire s&#39;ils n&#39;en ont pas déjà un :</p><ul><li><em>die Kinder</em> → <em>den Kinder<strong>n</strong></em> - <em>Ich helfe den Kindern.</em> (J&#39;aide les enfants.)</li><li><em>die Freunde</em> → <em>den Freunde<strong>n</strong></em> - <em>Er dankt den Freunden.</em> (Il remercie les amis.)</li><li><em>die Autos</em> → <em>den Autos</em> (déjà en -s, pas de changement)</li></ul>',23)])])}const f=t(n,[["render",i]]);export{p as __pageData,f as default};
